// // This comparator outputs 1 when signal_a is less than or equal to signal_b
module adc_comparator(  
    input [15:0] signal_a,  
    input [15:0] signal_b,  
    output reg greater  
);  

always @(*) begin  
    if (signal_a > signal_b)  
        greater = 1;  
    else  
        greater = 0;  
end  
endmodule
